mapper.select:
select

from biz_alipay_bill a inner join biz_accident c on a.accid = c.id inner join biz_wx_user d on c.openid = d.openid left join biz_alipay_pay_record b on a.id = b.bill_id


        and (a.pay_time between CONCAT(#{startTime},' 00:00:00') and CONCAT(#{endTime},' 00:00:00'))


        and a.status = #{payStatus}


        and b.alipay_account = #{alipayAccount}


ORDER BY a.create_time desc
